const input = $json.body;
const email = (input.email || '').trim().toLowerCase();
const name = (input.name || '').trim();

if (!email || !name) {
  return [{ json: { sent: false, error: 'Name and email required' } }];
}

const staticData = $getWorkflowStaticData('global');
const now = Date.now();

// Rate limit 60s
if (now - (staticData[email + '_lastSent'] || 0) < 60000) {
  return [{ json: { sent: false, error: 'Please wait 60s' } }];
}

const otp = Math.floor(100000 + Math.random() * 900000).toString();
staticData[email] = { otp, expires: now + 10 * 60 * 1000 };
staticData[email + '_lastSent'] = now;

return [{ json: {
  sent: true, 
  email, 
  name, 
  otp, 
  timestamp: new Date().toISOString().replace('T',' ').substring(0,19), 
  userAgent: $json.headers['user-agent'] || 'Unknown' 
} }];

const input = $json.body;
const email = (input.email || '').trim().toLowerCase();
const inputOtp = (input.otp || '').trim();
const name = (input.name || '').trim();

const staticData = $getWorkflowStaticData('global');
const stored = staticData[email];
const now = Date.now();

const headers = $json.headers || {};
const userAgent = headers['user-agent'] || 'Unknown';
const timestamp = new Date().toISOString().replace('T',' ').substring(0,19);

if (!stored) {
  return [{ json: { verified: false, error: 'No OTP found. Request a new one.',
    _action: 'OTP_FAILED', name, email, userAgent, timestamp } }];
}
if (now > stored.expires) {
  delete staticData[email];
  return [{ json: { verified: false, error: 'OTP expired.',
    _action: 'OTP_FAILED', name, email, userAgent, timestamp } }];
}
if (stored.otp !== inputOtp) {
  return [{ json: { verified: false, error: 'Invalid OTP.',
    _action: 'OTP_FAILED', name, email, userAgent, timestamp } }];
}

// Success - clean up
delete staticData[email];

return [{ json: { verified: true,
  _action: 'LOGIN_SUCCESS', name, email, userAgent, timestamp } }];

